/**
 * AllFreeAlerts — Voice Reel Generator
 * Generates a reel video WITH voiceover narration using Edge TTS
 * This is the "second daily video" — music-only reel is generated by generate_reel.js
 *
 * Usage: node generate_voice_reel.js [--dry-run]
 * Requires: ffmpeg, python (for beat generation), edge-tts (pip install edge-tts), puppeteer
 */

const { execSync, spawnSync } = require('child_process');
const fs = require('fs');
const path = require('path');

// ── Config ──
const DRY_RUN = process.argv.includes('--dry-run') || process.argv.includes('--preview');
const OUT_DIR = path.join(__dirname, 'tmp_videos');
const BEAT_FILE = path.join(OUT_DIR, 'beat.wav');
const VOICE_REEL_FILE = path.join(OUT_DIR, 'voice_reel.mp4');

// ── Brand ──
const COLORS = { teal: '#0ABAB5', orange: '#FF6F3C', gold: '#F5A623' };
const CAT_COLORS = { Sweepstakes: COLORS.teal, Freebies: COLORS.orange, Settlements: COLORS.gold };
const CAT_EMOJI = { Sweepstakes: '🎉', Freebies: '🎁', Settlements: '💰' };
const CAT_LABELS = { Sweepstakes: 'Sweepstakes', Freebies: 'Free Stuff', Settlements: 'Settlement' };

const THEMES = [
  { name: 'midnight', bg: 'linear-gradient(160deg, #0e1628 0%, #1a1a2e 50%, #0e1628 100%)' },
  { name: 'sunset', bg: 'linear-gradient(160deg, #1a0a2e 0%, #2d1b4e 40%, #1a0a2e 100%)' },
  { name: 'ocean', bg: 'linear-gradient(160deg, #0a1628 0%, #0d2137 50%, #0a1628 100%)' },
  { name: 'forest', bg: 'linear-gradient(160deg, #0a1a14 0%, #0d2e1f 50%, #0a1a14 100%)' },
  { name: 'ember', bg: 'linear-gradient(160deg, #1a0f0a 0%, #2e1810 50%, #1a0f0a 100%)' },
  { name: 'slate', bg: 'linear-gradient(160deg, #1a1a1a 0%, #2a2a2a 50%, #1a1a1a 100%)' },
  { name: 'arctic', bg: 'linear-gradient(160deg, #0a1520 0%, #102838 50%, #0a1520 100%)' },
];

// Use different theme than music-only reel (offset by 3)
function getTodayTheme() {
  const day = Math.floor(Date.now() / 86400000);
  return THEMES[(day + 3) % THEMES.length];
}

function log(msg) { console.log(`[VoiceReel] ${msg}`); }

// ── Load data ──
function loadData() {
  try {
    return JSON.parse(fs.readFileSync(path.join(__dirname, 'data', 'results.json'), 'utf8'));
  } catch {
    try {
      const raw = fs.readFileSync(path.join(__dirname, 'site', 'data.json'), 'utf8');
      const key = 'aFa2026xK';
      const b = Buffer.from(raw, 'base64');
      const decoded = Buffer.from(b.map((v, i) => v ^ key.charCodeAt(i % key.length)));
      return JSON.parse(decoded.toString('utf8'));
    } catch { return []; }
  }
}

function loadHistory() {
  try { return JSON.parse(fs.readFileSync(path.join(__dirname, 'ig_fb_post_history.json'), 'utf8')); }
  catch { return { posted: [] }; }
}

// Pick DIFFERENT deals than the music-only reel (offset selection)
function pickItems() {
  const data = loadData();
  const history = loadHistory();
  const postedLinks = new Set(history.posted || []);
  const picks = [];

  for (const cat of ['Sweepstakes', 'Freebies', 'Settlements']) {
    let catItems = data.filter(i => i.category === cat && !postedLinks.has(i.link));
    if (cat === 'Settlements') {
      catItems = catItems.filter(i => !i.scope || i.scope === 'nationwide');
    }
    if (catItems.length > 1) {
      // Use different offset than music reel to pick different deals
      const day = Math.floor(Date.now() / 86400000);
      const idx = (day * 11 + picks.length * 17 + 5) % catItems.length;
      picks.push({ category: cat, item: catItems[idx] });
    } else if (catItems.length === 1) {
      picks.push({ category: cat, item: catItems[0] });
    }
  }
  return picks;
}

// ── Generate voiceover scripts ──
function buildVoiceScripts(picks) {
  const totalData = loadData();
  const scripts = [];

  // Intro narration
  scripts.push({
    type: 'intro',
    text: `Here are today's top free stuff picks from All Free Alerts. ${totalData.length} plus active deals, found for you.`
  });

  // Deal narrations
  for (const { category, item } of picks) {
    const label = CAT_LABELS[category];
    const title = (item.title || '').replace(/[|—–]/g, ',').slice(0, 120);
    const summary = (item.prize_summary || item.description || '').slice(0, 100);

    let text = `${label}: ${title}.`;
    if (summary) text += ` ${summary}.`;

    // Add deadline urgency
    const deadline = item.end_date || item.deadline || '';
    if (deadline) {
      const d = new Date(deadline);
      if (!isNaN(d)) {
        const days = Math.max(0, Math.ceil((d - new Date()) / 86400000));
        if (days <= 14) text += ` Hurry, only ${days} days left!`;
      }
    }

    scripts.push({ type: 'deal', category, text });
  }

  // Outro narration
  scripts.push({
    type: 'outro',
    text: 'Follow All Free Alerts for daily deals. Link in bio for the full list.'
  });

  return scripts;
}

// ── Generate TTS audio files using Edge TTS ──
async function generateVoiceover(scripts) {
  log('Generating voiceover audio...');
  const voiceFiles = [];
  const voice = 'en-US-GuyNeural'; // Clear male voice

  for (let i = 0; i < scripts.length; i++) {
    const outFile = path.join(OUT_DIR, `voice_${i}.mp3`);
    const text = scripts[i].text.replace(/'/g, "'").replace(/"/g, '\\"');

    try {
      const cmd = `edge-tts --text "${text}" --voice ${voice} --rate=+5% --write-media "${outFile}"`;
      execSync(cmd, { stdio: 'pipe', timeout: 15000 });
      voiceFiles.push(outFile);
      log(`  Voice ${i}: ${scripts[i].type} (${scripts[i].text.substring(0, 50)}...)`);
    } catch (e) {
      log(`  Voice ${i} failed: ${e.message}`);
      // Create 3s silence as fallback
      execSync(`ffmpeg -y -f lavfi -i anullsrc=r=44100:cl=mono -t 3 "${outFile}"`, { stdio: 'pipe' });
      voiceFiles.push(outFile);
    }
  }

  // Get duration of each voice clip
  const durations = [];
  for (const file of voiceFiles) {
    try {
      const probe = execSync(`ffprobe -v error -show_entries format=duration -of csv=p=0 "${file}"`, { encoding: 'utf8' }).trim();
      durations.push(Math.max(parseFloat(probe) || 3, 2.5)); // minimum 2.5s per slide
    } catch {
      durations.push(3);
    }
  }

  return { voiceFiles, durations };
}

