// ── Render slides with Puppeteer ──
async function renderSlides(picks) {
  const puppeteer = require('puppeteer');
  const browser = await puppeteer.launch({ headless: 'new', args: ['--no-sandbox'] });
  const page = await browser.newPage();
  await page.setViewport({ width: 1080, height: 1920 });

  if (!fs.existsSync(OUT_DIR)) fs.mkdirSync(OUT_DIR, { recursive: true });

  const slides = [];
  const totalSlides = picks.length;
  const totalData = loadData();

  // Intro
  const introHTML = generateIntroSlideHTML(totalData.length);
  const introFile = path.join(OUT_DIR, 'vslide_intro.html');
  const introPNG = path.join(OUT_DIR, 'vslide_intro.png');
  fs.writeFileSync(introFile, introHTML);
  await page.goto('file:///' + introFile.replace(/\\/g, '/'));
  await page.screenshot({ path: introPNG });
  fs.unlinkSync(introFile);
  slides.push(introPNG);
  log('  Rendered intro slide');

  // Deal slides
  for (let i = 0; i < picks.length; i++) {
    const { category, item } = picks[i];
    const html = generateDealSlideHTML(item, category, i + 1, totalSlides);
    const htmlFile = path.join(OUT_DIR, `vslide_${i}.html`);
    const pngFile = path.join(OUT_DIR, `vslide_${i}.png`);
    fs.writeFileSync(htmlFile, html);
    await page.goto('file:///' + htmlFile.replace(/\\/g, '/'));
    await page.screenshot({ path: pngFile });
    fs.unlinkSync(htmlFile);
    slides.push(pngFile);
    log(`  Rendered deal slide ${i + 1}: ${item.title.substring(0, 40)}...`);
  }

  // Outro
  const outroHTML = generateOutroSlideHTML();
  const outroFile = path.join(OUT_DIR, 'vslide_outro.html');
  const outroPNG = path.join(OUT_DIR, 'vslide_outro.png');
  fs.writeFileSync(outroFile, outroHTML);
  await page.goto('file:///' + outroFile.replace(/\\/g, '/'));
  await page.screenshot({ path: outroPNG });
  fs.unlinkSync(outroFile);
  slides.push(outroPNG);
  log('  Rendered outro slide');

  await browser.close();
  return slides;
}

// ── Generate beat (reuse from generate_beat.py) ──
function generateBeat() {
  if (!fs.existsSync(OUT_DIR)) fs.mkdirSync(OUT_DIR, { recursive: true });
  if (fs.existsSync(BEAT_FILE)) {
    const stat = fs.statSync(BEAT_FILE);
    if (Date.now() - stat.mtimeMs < 86400000) {
      log('Reusing existing beat');
      return;
    }
  }
  log('Generating beat...');
  const pyCmd = process.platform === 'win32' ? 'python' : 'python3';
  const result = spawnSync(pyCmd, [path.join(__dirname, 'generate_beat.py'), BEAT_FILE], {
    stdio: 'pipe', timeout: 30000
  });
  if (result.status !== 0) {
    log('Beat generation failed, creating silent audio');
    execSync(`ffmpeg -y -f lavfi -i anullsrc=r=44100:cl=stereo -t 30 "${BEAT_FILE}"`, { stdio: 'pipe' });
  }
  log('Beat ready');
}

// ── Stitch video with voice + beat ──
function stitchVideo(slides, voiceFiles, durations) {
  log('Stitching video with voiceover...');

  // Add 1.5s padding to each voice duration for breathing room
  const slideDurations = durations.map(d => d + 1.5);
  const totalDur = slideDurations.reduce((a, b) => a + b, 0);
  log(`Total video duration: ${totalDur.toFixed(1)}s`);

  // Step 1: Create individual slide video clips (NO audio)
  const slideVideos = [];
  for (let i = 0; i < slides.length; i++) {
    const slideVid = path.join(OUT_DIR, `vclip_${i}.mp4`);
    const dur = slideDurations[i].toFixed(2);
    const zoomDir = i % 2 === 0 ? '1+0.0006*on' : '1.10-0.0006*on';
    const frames = Math.ceil(slideDurations[i] * 30);

    const cmd = `ffmpeg -y -loop 1 -t ${dur} -i "${slides[i]}" -filter_complex "[0:v]scale=1080:1920,zoompan=z='${zoomDir}':x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':d=${frames}:s=1080x1920:fps=30[v]" -map "[v]" -t ${dur} -c:v libx264 -preset ultrafast -crf 26 -pix_fmt yuv420p -r 30 -an "${slideVid}"`;

    try {
      execSync(cmd, { stdio: 'pipe', timeout: 120000 });
      slideVideos.push(slideVid);
      log(`  Clip ${i} done (${dur}s)`);
    } catch (e) {
      log(`  Clip ${i} failed: ${e.stderr?.toString().split('\n').slice(-3).join('\n') || e.message}`);
      return false;
    }
  }

  // Step 2: Concatenate video clips (no audio)
  const listFile = path.join(OUT_DIR, 'voice_clips.txt');
  fs.writeFileSync(listFile, slideVideos.map(f => `file '${f.replace(/\\/g, '/')}'`).join('\n'));
  const silentVideo = path.join(OUT_DIR, 'voice_reel_silent.mp4');
  execSync(`ffmpeg -y -f concat -safe 0 -i "${listFile}" -c copy "${silentVideo}"`, { stdio: 'pipe', timeout: 30000 });
  log('Video concatenated');

  // Step 3: Create continuous voice track (pad each voice to slide duration, then concat)
  const voiceTrack = path.join(OUT_DIR, 'voice_track.wav');
  let voiceFilter = '';
  let voiceConcat = '';
  let voiceInputs = '';
  for (let i = 0; i < voiceFiles.length; i++) {
    voiceInputs += ` -i "${voiceFiles[i]}"`;
    voiceFilter += `[${i}:a]aformat=sample_fmts=fltp:sample_rates=44100:channel_layouts=mono,apad=whole_dur=${slideDurations[i].toFixed(2)},atrim=0:${slideDurations[i].toFixed(2)}[vp${i}];`;
    voiceConcat += `[vp${i}]`;
  }
  voiceFilter += `${voiceConcat}concat=n=${voiceFiles.length}:v=0:a=1[out]`;
  execSync(`ffmpeg -y${voiceInputs} -filter_complex "${voiceFilter}" -map "[out]" "${voiceTrack}"`, { stdio: 'pipe', timeout: 30000 });
  log('Voice track created');

  // Step 4: Mix continuous beat + continuous voice, merge with video
  const finalCmd = `ffmpeg -y -i "${silentVideo}" -i "${voiceTrack}" -i "${BEAT_FILE}" -filter_complex "[1:a]volume=1.0[voice];[2:a]volume=0.35,aloop=loop=-1:size=44100*25[beatloop];[voice][beatloop]amix=inputs=2:duration=first:dropout_transition=0[outa]" -map 0:v -map "[outa]" -c:v copy -c:a aac -b:a 128k -shortest "${VOICE_REEL_FILE}"`;

  try {
    execSync(finalCmd, { stdio: 'pipe', timeout: 60000 });
    const size = (fs.statSync(VOICE_REEL_FILE).size / 1024 / 1024).toFixed(1);
    log(`Voice reel generated: ${VOICE_REEL_FILE} (${size} MB)`);
    return true;
  } catch (e) {
    log('FFmpeg error: ' + (e.stderr?.toString().split('\n').slice(-10).join('\n') || e.message));
    return false;
  }
}

// ── Main ──
async function main() {
  log('=== Voice Reel Generator ===');
  log(`Mode: ${DRY_RUN ? 'DRY RUN' : 'LIVE'}`);

  if (!fs.existsSync(OUT_DIR)) fs.mkdirSync(OUT_DIR, { recursive: true });

  // Pick deals
  const picks = pickItems();
  if (picks.length === 0) {
    log('No deals to feature!');
    return;
  }
  log(`Picked ${picks.length} deals:`);
  picks.forEach(p => log(`  ${p.category}: ${p.item.title.substring(0, 50)}`));

  // Build voice scripts
  const scripts = buildVoiceScripts(picks);
  log('\nVoice scripts:');
  scripts.forEach((s, i) => log(`  ${i}: [${s.type}] ${s.text.substring(0, 60)}...`));

  // Generate voiceover audio
  const { voiceFiles, durations } = await generateVoiceover(scripts);
  log(`\nSlide durations: ${durations.map(d => d.toFixed(1) + 's').join(', ')}`);
  const totalDuration = durations.reduce((a, b) => a + b + 1.5, 0);
  log(`Total estimated duration: ${totalDuration.toFixed(1)}s`);

  if (DRY_RUN) {
    log('\nDRY RUN — skipping slide rendering and video stitching');
    log('Voice files generated in: ' + OUT_DIR);
    return;
  }

  // Generate beat
  generateBeat();

  // Render slides
  log('\nRendering slides...');
  const slides = await renderSlides(picks);

  // Stitch video
  const success = stitchVideo(slides, voiceFiles, durations);
  if (!success) {
    log('Video generation failed!');
    process.exit(1);
  }

  log('\nDone! Voice reel saved to: ' + VOICE_REEL_FILE);
}

main().catch(e => {
  console.error('Fatal error:', e);
  process.exit(1);
});
